import React from "react";

// MUI Imports
import HomeIcon from "@mui/icons-material/Home";
import CodeIcon from "@mui/icons-material/Code";
import FolderOpenIcon from "@mui/icons-material/FolderOpen";
import MailOutlineIcon from "@mui/icons-material/MailOutline";

// Local Imports
import { useLanguage } from "../../context/LanguageContext";

// Styles
import "./Dock.scss";

interface DockProps {
  activeIndex: number;
  sectionIds: string[];
  style?: React.CSSProperties;
}

const dockItems = [
  { icon: <HomeIcon />, labelKey: "nav.home" },
  { icon: <CodeIcon />, labelKey: "nav.skills" },
  { icon: <FolderOpenIcon />, labelKey: "nav.projects" },
  { icon: <MailOutlineIcon />, labelKey: "nav.contact" },
];

const Dock: React.FC<DockProps> = ({ activeIndex, sectionIds, style }) => {
  const { t } = useLanguage();

  const scrollTo = (id: string) => {
    const el = document.getElementById(id);
    if (el) {
      el.scrollIntoView({ behavior: "smooth", block: "start" });
    }
  };

  return (
    <nav className="dock" aria-label="Site navigation" style={style}>
      <div className="dock-track">
        <div className="contactanimate1" />
        <div className="contactanimate2" />
        {dockItems.map((item, index) => (
          <button
            key={index}
            className={`dock-item ${index === activeIndex ? "dock-item--active" : ""}`}
            onClick={() => scrollTo(sectionIds[index])}
            aria-label={t(item.labelKey)}
            title={t(item.labelKey)}
          >
            <span className="dock-icon">{item.icon}</span>
            <span className="dock-label">{t(item.labelKey)}</span>
            {index === activeIndex && <span className="dock-indicator" />}
          </button>
        ))}
      </div>
    </nav>
  );
};

export default Dock;
